sql:
SELECT ad_id
FROM ad_performance
WHERE clicks = (SELECT MAX(clicks) FROM ad_performance);

SELECT COUNT(*) 
FROM user_ads 
WHERE clicked_on_ad = 1;

external_knowledge:
- "Surprisingly high interest" refers to a click-through rate greater than 0.04; 
- "No engagement" means the ad has received 0 clicks;
- "Where are these ads located" means we want to know the city and country where the ads are being shown.

sql:
SELECT ad_id, SUM(impressions) AS total_impressions
FROM ad_performance
GROUP BY ad_id;

SELECT user_id, interest
FROM user_interests
WHERE interest = 'Tech';

SELECT DISTINCT user_id
FROM user_ads
WHERE clicked_on_ad = 1;

SELECT COUNT(DISTINCT user_id) AS total_clicked_users
FROM user_ads
WHERE clicked_on_ad = 1;

SELECT AVG(area_income) AS average_area_income
FROM users
WHERE daily_internet_usage > 100;

SELECT SUM(click_through_rate) AS total_click_through_rate, SUM(conversion_rate) AS total_conversion_rate
FROM ad_performance
WHERE ad_id IN (
  SELECT ad_id FROM user_ads WHERE user_id IN (
    SELECT user_id FROM users WHERE daily_internet_usage > 150
  )
);

SELECT ad_id
FROM ad_performance
WHERE click_through_rate < (SELECT AVG(click_through_rate) FROM ad_performance);

SELECT user_id, daily_internet_usage
FROM users
WHERE daily_internet_usage = (SELECT MAX(daily_internet_usage) FROM users);
